parameters.jsCode:
function montarMensagem(template, params) {
  if (!template) return "";
  let msg = template;
  params.forEach((valor, index) => {
    const placeholder = new RegExp(`{{\\s*${index + 1}\\s*}}`, 'g');
    msg = msg.replace(placeholder, valor ?? "");
  });
  return msg;
}

function normalizeTelefone(raw) {
  if (raw == null) return "";
  let d = String(raw).replace(/\D/g, "").replace(/^0+/, "");
  return d ? (d.startsWith("55") ? d : "55" + d) : "";
}

return items.map((item) => {
  const mensagem       = item.json?.mensagem || "";
  const nome           = item.json?.nome || "";
  const telefone       = normalizeTelefone(item.json?.telefone);
  const template_name  = item.json?.template_name || "";
  const status         = item.json?.status || "";
  const requires_image = item.json?.requires_image || "";
  const participant_id = item.json?.participant_id;
  const imagem_url     = (item.json?.imagem || "").toString().trim();

  const params = [];
  const paramsObj = {};
  Object.keys(item.json).forEach(key => {
    if (key.startsWith("param_")) {
      const index = Number(key.replace("param_", ""));
      params[index] = item.json[key];
      paramsObj[key] = item.json[key];
    }
  });

  const mensagem_completa = montarMensagem(mensagem, params);

  return {
    json: {
      participant_id,
      telefone,
      nome,
      status,
      template_name,
      mensagem_completa,
      requires_image,
      imagem_url,
      total_params: params.length,
      ...paramsObj
    }
  };
});

const items = $input.all().map(i => i.json);

const template = items.find(i => i.message_template);
const event = items.find(i => i.event_date && i.title);

const participants = items.filter(i =>
  i.phone &&
  !i.message_template &&
  !i.title &&
  !i.contact_person
);

function normalizePhone(phone) {
  if (!phone) return null;
  let digits = String(phone).replace(/\D/g, '');
  if (digits.length >= 10 && digits.length <= 11) digits = '55' + digits;
  return digits;
}

function isValid(value) {
  return value !== null && value !== undefined && String(value).trim() !== '';
}

return participants.map(participant => {

  const voucher = participant.voucher_data || {};

  // 🔹 PARAMS DO TEMPLATE
  const parameters = (template.variables || []).map((_, index) => {
    const key = `{{${index + 1}}}`;
    let value = voucher[key];

    if (value != null) {
      value = String(value)
        .replace(/\r/g, '')
        .replace(/\t/g, ' ')
        .replace(/ {4,}/g, '   ');
    } else {
      value = '';
    }

    return value;
  });

  // 🔹 MENSAGEM FORMATADA
  const mensagem_formatada = voucher.mensagem_formatada || '';

  // 🔥 DETECÇÃO SEGURA DE MÍDIA (NULL SAFE)
  const webhookBody = $('Webhook').first().json.body;

  let imagem_url = '';
  let header_type = 'none';

  if (isValid(webhookBody?.document_url)) {
    imagem_url = webhookBody.document_url;
    header_type = 'document';
  } 
  else if (isValid(webhookBody?.message_image_url)) {
    imagem_url = webhookBody.message_image_url;
    header_type = 'image';
  }

  // 🔹 PARAMS DINÂMICOS
  const paramObj = {};
  parameters.forEach((val, i) => {
    paramObj[`param_${i}`] = val;
  });

  return {
    json: {
      participant_id:   participant.id,
      event_id:         participant.event_id,
      phone:            normalizePhone(participant.phone),
      nome:             participant.name,
      status:           participant.status,
      template_name:    template.meta_template_name,
      mensagem:         template.message_template,
      requires_image:   template.requires_image,
      phone_number_id:  event?.whatsapp_number_id ?? '',

      // 🔥 ESSENCIAL
      imagem_url,
      header_type,
      mensagem_formatada,

      total_params: parameters.length,
      ...paramObj
    }
  };
});

return $input.all().map(item => {
  const json = item.json;

  const output = {
    template_name:   json.template_name,
    mensagem:        json.mensagem,
    imagem:          json.imagem_url, // ← vem já preenchido do nó anterior
    nome:            json.nome,
    telefone:        json.phone,
    status:          json.status,
    requires_image:  json.requires_image,
    event_id:        json.event_id,
    participant_id:  json.participant_id,
    phone_number_id: $('Webhook').first().json.body.phone_number_id,
    imagem_url:      json.imagem_url,
    total_params:    json.total_params
  };

  Object.keys(json).forEach(key => {
    if (key.startsWith('param_')) {
      output[key] = json[key];
    }
  });

  return { json: output };
});

